operation.add:
// OpenCart Filter: make the module edit route available even when the marketplace install cache was not rebuilt yet.
if (is_dir(DIR_EXTENSION . 'opencart_filter/')) {
	$this->autoloader->register('Opencart\Admin\Controller\Extension\OpencartFilter', DIR_EXTENSION . 'opencart_filter/admin/controller/');
	$this->autoloader->register('Opencart\Admin\Model\Extension\OpencartFilter', DIR_EXTENSION . 'opencart_filter/admin/model/');
	$this->autoloader->register('Opencart\System\Library\Extension\OpencartFilter', DIR_EXTENSION . 'opencart_filter/system/library/');
	$this->template->addPath('extension/opencart_filter', DIR_EXTENSION . 'opencart_filter/admin/view/template/');
	$this->language->addPath('extension/opencart_filter', DIR_EXTENSION . 'opencart_filter/admin/language/');
	$this->config->addPath('extension/opencart_filter', DIR_EXTENSION . 'opencart_filter/system/config/');
}

// OpenCart Filter: make storefront AJAX routes available even when the marketplace install cache was not rebuilt yet.
if (is_dir(DIR_EXTENSION . 'opencart_filter/')) {
	$this->autoloader->register('Opencart\Catalog\Controller\Extension\OpencartFilter', DIR_EXTENSION . 'opencart_filter/catalog/controller/');
	$this->autoloader->register('Opencart\Catalog\Model\Extension\OpencartFilter', DIR_EXTENSION . 'opencart_filter/catalog/model/');
	$this->autoloader->register('Opencart\System\Library\Extension\OpencartFilter', DIR_EXTENSION . 'opencart_filter/system/library/');
	$this->template->addPath('extension/opencart_filter', DIR_EXTENSION . 'opencart_filter/catalog/view/template/');
	$this->language->addPath('extension/opencart_filter', DIR_EXTENSION . 'opencart_filter/catalog/language/');
	$this->config->addPath('extension/opencart_filter', DIR_EXTENSION . 'opencart_filter/system/config/');
}
